module multi_pipe_8bit(
    input clk,
    input rst_n,
    input mul_en_in,
    input [7:0] mul_a,
    input [7:0] mul_b,
    output mul_en_out,
    output [15:0] mul_out
);
    // TODO: implement your 8-bit multiplier design here, then delete this comment
    // ...
    input wire [1:0] mul_en_out_reg;
    input wire [7:0] mul_a_reg;
    input wire [7:0] mul_b_reg;
    input wire [15:0] sum;
    input wire [15:0] mul_out_reg;
    input wire [15:0] temp;
    always @(posedge clk) begin
        mul_en_out_reg <= {mul_en_out_reg[0], mul_en_in};
    end
    assign mul_en_out = mul_en_out_reg[1];
    always @(posedge clk) begin
        if (mul_en_out_reg[1]) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
        end
    end
    assign temp[0] = mul_en_out_reg[1] ? mul_a_reg[0] & mul_b_reg[0] : 1'b0;
    assign temp[1] = mul_en_out_reg[1] ? mul_a_reg[1] & mul_b_reg[0] : 1'b0;
    assign temp[2] = mul_en_out_reg[1] ? mul_a_reg[2] & mul_b_reg[0] : 1'b0;
    assign temp[3] = mul_en_out_reg[1] ? mul_a_reg[3] & mul_b_reg[0] : 1'b0;
    assign temp[4] = mul_en_out_reg[1] ? mul_a_reg[4] & mul_b_reg[0] : 1'b0;
    assign temp[5] = mul_en_out_reg[1] ? mul_a_reg[5] & mul_b_reg[0] : 1'b0;
    assign temp[6] = mul_en_out_reg[1] ? mul_a_reg[6] & mul_b_reg[0] : 1'b0;
    assign temp[7] = mul_en_out_reg[1] ? mul_a_reg[7] & mul_b_reg[0] : 1'b0;
    assign temp[8] = mul_en_out_reg[1] ? mul_a_reg[0] & mul_b_reg[1] : 1'b0;
    assign temp[9] = mul_en_out_reg[1] ? mul_a_reg[1] & mul_b_reg[1] : 1'b0;
    assign temp[10] = mul_en_out_reg[1] ? mul_a_reg[2] & mul_b_reg[1] : 1'b0;
    assign temp[11] = mul_en_out_reg[1] ? mul_a_reg[3] & mul_b_reg[1] : 1'b0;
    assign temp[12] = mul_en_out_reg[1] ? mul_a_reg[4] & mul_b_reg[1] : 1'b0;
    assign temp[13] = mul_en_out_reg[1] ? mul_a_reg[5] & mul_b_reg[1] : 1'b0;
    assign temp[14] = mul_en_out_reg[1] ? mul_a_reg[6] & mul_b_reg[1] : 1'b0;
    assign temp[15] = mul_en_out_reg[1] ? mul_a_reg[7] & mul_b_reg[1] : 1'b0;
    always @(posedge clk) begin
        if (mul_en_out_reg[1]) begin
            sum[0] <= temp[0];
            sum[1] <= temp[1];
            sum[2] <= temp[2];
            sum[3] <= temp[3];
            sum[4] <= temp[4];
            sum[5] <= temp[5];
            sum[6] <= temp[6];
            sum[7] <= temp[7];
            sum[8] <= temp[8];
            sum[9] <= temp[9];
            sum[10] <= temp[10];
            sum[11] <= temp[11];
            sum[12] <= temp[12];
            sum[13] <= temp[13];
            sum[14] <= temp[14];
            sum[15] <= temp[15];
        end
    end
    always @(posedge clk) begin
        mul_out_reg <= mul_out_reg + sum;
    end
    assign mul_out = mul_en_out_reg[1] ? mul_out_reg : 16'b0;
endmodule
